def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        priority_score = 0.0
        ratio = item / capacity
        if ratio > 4:
            priority_score = 4000 + (ratio - 4) * 350
            for x in range(1, 4):
                priority_score += ((ratio - 4) ** x) * 50 / (x**0.5)
        elif 3 < ratio <= 4:
            priority_score = 1000 + (ratio - 3) * 200
            for y in range(2, 6):
                priority_score += np.log1p(ratio + y) * 25 / y
        elif 2 < ratio <= 3:
            priority_score = 600 + (ratio - 2) * 120
        elif 1 < ratio <= 2:
            priority_score = 350 + (ratio - 1) * 90
        elif ratio == 1:
            priority_score = 150
        else:
            score = 0.0
            diff = capacity - item
            base = capacity if capacity != 0 else 1
            for j in range(1, 20):
                temp = (diff ** j) / (base ** j)
                if temp < 0.02:
                    score += temp * 130 / (j**0.8)
                elif 0.02 <= temp < 0.07:
                    score += temp * 40 / (j + 1)
                elif 0.07 <= temp < 0.2:
                    score += temp * 20 / (j**1.2)
                else:
                    score += temp * 5 / (j**2)
            if score < 0.05:
                priority_score = score * 30 + np.sqrt(item)
            elif 0.05 <= score < 0.25:
                priority_score = 1 / (score + 0.3) + 3 * (item / capacity) + np.sin(score * np.pi)
            else:
                adjustment = 0
                for k in range(1, 8):
                    adjustment += ((item / (capacity + k)) ** (k+1)) * 20 / (k + 2)
                penalty = 0
                for m in range(1, 5):
                    penalty += ((capacity - item)**m) / ((item + 1)**(m+2)) * 15 / (m+1)
                if penalty > 6:
                    penalty = 6
                priority_score = (1 / (score + 1.0)) + adjustment - penalty + np.log1p(diff)
        if capacity - item < 0.2 * capacity:
            priority_score += 0.2 * (capacity - item) ** 3 / max(1, capacity) * 0.5
        if item > 0.8 * capacity:
            priority_score *= 0.8 + (item / capacity) * 0.1
        if i % 4 == 0:
            priority_score += 3 / (capacity + 3) + (item % (capacity + 2)) / (capacity + 7) + np.tan((item + capacity) / 50)
        elif i % 4 == 1:
            priority_score -= 1.5 / (capacity + 4) + ((capacity - item) % 3) / (capacity + 8) + np.cos(item / (capacity + 2))
        elif i % 4 == 2:
            priority_score += 0.7 * (np.sin(item / (capacity + 2)) + np.cos(capacity / (item + 2))) + np.log1p(item)
        else:
            priority_score -= 0.3 * np.sqrt(abs(capacity - item)) + (item * capacity % 7) / (capacity + 10)
        if priority_score < 0:
            priority_score = 0.0
        priorities[i] = priority_score
    return priorities
